        import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;
import java.util.HashMap;
import java.util.PriorityQueue;
import java.util.TreeSet;

public class Adrese {
	// numarul initial de persoane
	int n;
	// map care leaga un email de numele primei persoane careia i-a fost
	// atribuit acest mail
	HashMap<String, Integer> firstPerson;
	// vector de persoane
	Person[] people;
	// vector pentru persoanele vizitate (folosit in DFS)
	boolean[] visitedPeople;
	// heap folosit pentru a extrage rezultatele in ordinea dorita
	PriorityQueue<Person> pq;
	// numele corespunzator unei componente conexe
	String namePerson;
	// functie care citeste datele de intrare si prelucreaza graful
	public void readInput(String filename) {
		MyScanner sc = new MyScanner(filename);
		n = sc.nextInt();
		people = new Person[n];
		visitedPeople = new boolean[n];
		firstPerson = new HashMap<>();
		pq = new PriorityQueue<>();
		// citeste datele fiecarei persoane
		for (int i = 0; i < n; i++) {
			String name = sc.next();
			int nrEmails = sc.nextInt();
			// adauga o noua persoana
			people[i] = new Person(name, nrEmails);
			// citeste emailurile
			for (int j = 0; j < nrEmails; j++) {
				String email = sc.nextLine();
				// daca emailul nu a fost deja intalnit aceasta este prima
				// persoana careia ii este atribuit mailul asta
				if (!firstPerson.containsKey(email)) {
					firstPerson.put(email, i);
					// adaugam emailul in multimea persoanei
					people[i].addEmail(email);
				} else {
					// altfel, extragem indexul primei persoane care a avut
					// acest email
					int index = firstPerson.get(email);
					// legam direct cele doua persoane
					people[i].addSame(index);
					people[index].addSame(i);
				}
			}
		}
	}
	// functie auxiliara pentru DFS
	// in urma apelarii sale o sa obtinem numele persoanei si emailurile
	// corespunzatoare componentei conexe
	public void dfsRec(int index, TreeSet<String> allEmails) {
		// persoana curenta
		Person current = people[index];
		// marcheaza ca vizitata
		visitedPeople[index] = true;
		// adauga toate emailurile persoanei
		allEmails.addAll(current.getEmails());
		// updateaza numele componentei conexe daca poate
		if (current.getName().compareTo(namePerson) < 0) {
			namePerson = current.getName();
		}
		// parcurge persoanele cu emailuri similare cu persoana curenta
		// si care nu au fost deja vizitate
		for (Integer same : current.getSame()) {
			if (visitedPeople[same] == false) {
				dfsRec(same, allEmails);
			}
		}
	}
	// functia principala dfs
	public void dfs() {
		for (int i = 0; i < n; i++) {
			if (visitedPeople[i] == false) {
				// extrage componenta conexa si creeaza o noua persoana
				// cu datele obtinute, pe care o pune in Heap
				TreeSet<String> allEmails = new TreeSet<>();
				namePerson = people[i].getName();
				dfsRec(i, allEmails);
				Person person = new Person(namePerson, allEmails.size());
				person.setEmails(allEmails);
				pq.add(person);
			}
		}
	}

	public static void main(String[] args) throws IOException {
		Adrese obj = new Adrese();
		// citeste datele
		obj.readInput("adrese.in");
		// obtine heap-ul cu persoanele
		obj.dfs();
		// deschide fisierul de iesire
		FileWriter fw = new FileWriter("adrese.out");
		BufferedWriter bw = new BufferedWriter(fw);
		PriorityQueue<Person> pq = obj.pq;
		// scrie numarul de persoane
		bw.write(pq.size() + "\n");
		// scrie datele fiecarei persoane, in ordinea ceruta in enunt
		while (!pq.isEmpty()) {
			Person current = pq.poll();
			bw.write(current.getName() + " " + current.getNrEmails() + "\n");
			for (String email : current.getEmails()) {
				bw.write(email + "\n");
			}
		}
		// inchide fisierul de iesire
		bw.close();
	}
}

